<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>2048 Dark</title>
    <style>
        body {
            background-color: #1a1a1a;
            color: #eee;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
            overflow: hidden;
        }
        .header {
            text-align: center;
            margin-bottom: 20px;
        }
        h1 {
            font-size: 48px;
            margin: 0;
        }
        .stats {
            display: flex;
            gap: 20px;
            align-items: center;
            justify-content: center;
            margin-bottom: 20px;
        }
        #score-container {
            background: #333;
            padding: 10px 20px;
            border-radius: 5px;
            font-weight: bold;
            font-size: 20px;
        }
        #reset {
            padding: 10px 20px;
            background: #8f7a66;
            color: white;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            font-weight: bold;
            font-size: 16px;
        }
        #reset:hover {
            background: #a69382;
        }
        #board {
            display: grid;
            grid-template-columns: repeat(4, 80px);
            grid-template-rows: repeat(4, 80px);
            gap: 10px;
            background-color: #bbada0;
            padding: 10px;
            border-radius: 6px;
            user-select: none;
        }
        .tile {
            width: 80px;
            height: 80px;
            background-color: rgba(238, 228, 218, 0.35);
            border-radius: 3px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 24px;
            font-weight: bold;
            color: #776e65;
        }
        /* Tile Colors */
        .tile-2 { background: #eee4da; color: #776e65; }
        .tile-4 { background: #ede0c8; color: #776e65; }
        .tile-8 { background: #f2b179; color: white; }
        .tile-16 { background: #f59563; color: white; }
        .tile-32 { background: #f67c5f; color: white; }
        .tile-64 { background: #f65e3b; color: white; }
        .tile-128 { background: #edcc61; color: white; font-size: 20px; }
        .tile-256 { background: #edcc61; color: white; font-size: 20px; }
        .tile-512 { background: #edcc61; color: white; font-size: 20px; }
        .tile-1024 { background: #edcc61; color: white; font-size: 16px; }
        .tile-2048 { background: #edcc61; color: white; font-size: 16px; }
    </style>
</head>
<body>

    <div class="header">
        <h1>2048</h1>
    </div>

    <div class="stats">
        <div id="score-container">Score: <span id="score">0</span></div>
        <button id="reset">New Game</button>
    </div>

    <div id="board"></div>

    <script>
        const boardEl = document.getElementById('board');
        const scoreEl = document.getElementById('score');
        const resetBtn = document.getElementById('reset');

        let grid = [];
        let currentScore = 0;

        function initGame() {
            grid = Array(4).fill(null).map(() => Array(4).fill(0));
            currentScore = 0;
            spawnTile();
            spawnTile();
            render();
        }

        function spawnTile() {
            const emptyCells = [];
            for (let r = 0; r < 4; r++) {
                for (let c = 0; c < 4; c++) {
                    if (grid[r][c] === 0) emptyCells.push({r, c});
                }
            }
            if (emptyCells.length > 0) {
                const {r, c} = emptyCells[Math.floor(Math.random() * emptyCells.length)];
                grid[r][c] = Math.random() < 0.9 ? 2 : 4;
            }
        }

        function render() {
            boardEl.innerHTML = '';
            for (let r = 0; r < 4; r++) {
                for (let c = 0; c < 4; c++) {
                    const val = grid[r][c];
                    const div = document.createElement('div');
                    div.className = 'tile' + (val > 0 ? ` tile-${val}` : '');
                    div.textContent = val === 0 ? '' : val;
                    boardEl.appendChild(div);
                }
            }
            scoreEl.textContent = currentScore;
        }

        function slideAndMerge(row) {
            // Remove zeros
            let filtered = row.filter(v => v !== 0);
            let merged = [];
            let scoreGain = 0;

            for (let i = 0; i < filtered.length; i++) {
                if (i < filtered.length - 1 && filtered[i] === filtered[i+1]) {
                    const newVal = filtered[i] * 2;
                    merged.push(newVal);
                    scoreGain += newVal;
                    i++; // Skip next
                } else {
                    merged.push(filtered[i]);
                }
            }

            while (merged.length < 4) {
                merged.push(0);
            }
            return { row: merged, scoreGain };
        }

        function move(direction) {
            let oldGrid = JSON.stringify(grid);
            let totalScoreGain = 0;

            if (direction === 'left') {
                for (let r = 0; r < 4; r++) {
                    const result = slideAndMerge(grid[r]);
                    grid[r] = result.row;
                    totalScoreGain += result.scoreGain;
                }
            } else if (direction === 'right') {
                for (let r = 0; r < 4; r++) {
                    const rowRev = [...grid[r]].reverse();
                    const result = slideAndMerge(rowRev);
                    grid[r] = result.row.reverse();
                    totalScoreGain += result.scoreGain;
                }
            } else if (direction === 'up') {
                for (let c = 0; c < 4; c++) {
                    const col = [grid[0][c], grid[1][c], grid[2][c], grid[3][c]];
                    const result = slideAndMerge(col);
                    for (let r = 0; r < 4; r++) grid[r][c] = result.row[r];
                    totalScoreGain += result.scoreGain;
                }
            } else if (direction === 'down') {
                for (let c = 0; c < 4; c++) {
                    const col = [grid[3][c], grid[2][c], grid[1][c], grid[0][c]];
                    const result = slideAndMerge(col);
                    for (let r = 0; r < 4; r++) grid[3-r][c] = result.row[r];
                    totalScoreGain += result.scoreGain;
                }
            }

            currentScore += totalScoreGain;
            const changed = oldGrid !== JSON.stringify(grid);

            if (changed) {
                spawnTile();
            }

            render();
            return changed;
        }

        // Programmatic API
        window.game = {
            size: 4,
            reset: function() {
                initGame();
            },
            move: function(dir) {
                return move(dir);
            },
            board: function() {
                return grid;
            },
            setBoard: function(arr) {
                grid = JSON.parse(JSON.stringify(arr));
                render();
            },
            score: function() {
                return currentScore;
            }
        };

        // Event Listeners
        window.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowLeft') window.game.move('left');
            else if (e.key === 'ArrowRight') window.game.move('right');
            else if (e.key === 'ArrowUp') window.game.move('up');
            else if (e.key === 'ArrowDown') window.game.move('down');
        });

        resetBtn.addEventListener('click', () => {
            window.game.reset();
        });

        // Start game on load
        initGame();
    </script>
</body>
</html>
